import { ulid } from 'ulid';

import type { BaseEventMessage } from '../messages/CommandRanMessage';

// Legacy support for vscode-otel, planned to be removed in the future
export type BaseEvent = BaseEventMessage;
export type CloudEventBaseData = Omit<BaseEventMessage, 'id' | 'object' | 'specversion' | 'datacontenttype' | 'source' | 'time'>;
export type MapToCloudEventBaseOptions = Omit<CloudEventBaseData, 'type' | 'data'>;

import type { CommandRanMessage } from '../messages/CommandRanMessage';
export type AllMessages =
  | CommandRanMessage

// Extract event type from message
type MessageType<T> = T extends { type: infer U } ? U : never;
export type EventType = MessageType<AllMessages>;

// Extract data from message
type ExtractData<T> = T extends { data: infer D } ? D : undefined;

// Auto-generated mapping from event type to data type
type MessageDataMap = {
  [K in EventType]: ExtractData<Extract<AllMessages, { type: K }>>;
};

export type EventPayload<TEventType extends EventType> = MessageDataMap[TEventType];
export type GetEventData<T extends EventType> = EventPayload<T>;

export interface CloudEvent<T extends EventType = EventType> extends CloudEventMapperResult {
  data?: EventPayload<T>;
}

/** Actor per cloudevent-structure.md: id, object, uri. */
export interface CloudEventActor {
  id?: string | null;
  object: string;
  uri: string | null;
}

export interface CloudEventDataItem {
  id?: string | null;
  object?: string | null;
  uri: string;
  [key: string]: unknown;
}

export interface CloudEventAnalyticsMetadata {
  userId?: string;
  userIpAddress?: string;
}

/**
 * Base CloudEvent structure. Template adds CloudEvent<T> extends CloudEventMapperResult.
 * Must be standalone (not alias of CloudEvent) to avoid recursive type error.
 */
export interface CloudEventMapperResult {
  id: string;
  specversion: string;
  object: string;
  datacontenttype: string;
  type: string;
  time: string | Date;
  origin: string;
  category?: 'product' | 'system';
  signal?: 'log' | 'trace' | 'metric';
  source?: string;
  subject?: string;
  subjects?: CloudEventActor[];
  /** API: CloudEventDataItem[]. UI: Record. CloudEvent<T> narrows to EventPayload<T>. */
  data?: unknown;
  actor?: CloudEventActor | null;
  /** @deprecated Use actor */
  requestId?: string;
  analyticsMetadata?: CloudEventAnalyticsMetadata;
  organization?: { id: string; slug: string };
  project?: { id: string; slug: string };
  organizationId?: string;
  organizationSlug?: string;
  projectId?: string;
  projectSlug?: string;
  /** @deprecated Prefer clientIp at root */
  context?: { ip?: string };
  osPlatform?: string;
  userAgent?: string;
  [key: string]: unknown;
}

/** Standard CloudEvent keys (handled by base mapper). Used to identify extension attributes. */
export const CLOUD_EVENT_STANDARD_KEYS: readonly (keyof CloudEventMapperResult)[] = [
  'id',
  'specversion',
  'object',
  'datacontenttype',
  'type',
  'time',
  'origin',
  'category',
  'signal',
  'source',
  'subject',
  'subjects',
  'data',
  'actor',
  'requestId',
  'analyticsMetadata',
  'organization',
  'project',
  'organizationId',
  'organizationSlug',
  'projectId',
  'projectSlug',
  'osPlatform',
  'userAgent',
  'context',
] as const;

export type CloudEventMapperAnalyticsMetadata = CloudEventAnalyticsMetadata;
export type CloudEventMapperActor = CloudEventActor;
export type CloudEventMapperDataItem = CloudEventDataItem;
export type CloudEventMapperSubjectsArray = CloudEventActor[];
export type CloudEventSubject = CloudEventActor;

export type MapToCloudEventOptions = Pick<
  CloudEventMapperResult,
  | 'type'
  | 'data'
  | 'actor'
  | 'requestId'
  | 'analyticsMetadata'
  | 'subjects'
  | 'category'
  | 'signal'
  | 'organizationId'
  | 'organizationSlug'
  | 'projectId'
  | 'projectSlug'
  | 'osPlatform'
  | 'userAgent'
> & {
  origin: string;
  source?: string;
  namespace?: string;
};

/**
 * Unified CloudEvent mapper.
 * Handles both API-side (event-bus) and UI-side (telemetry client) mappings.
 */

export function mapToCloudEvent<T extends EventType>(
  options: Omit<MapToCloudEventOptions, 'type' | 'data'> & {
    type: T;
    data?: EventPayload<T>;
  }
): CloudEvent<T>;

export function mapToCloudEvent<TResult extends CloudEventMapperResult>(
  options: MapToCloudEventOptions,
): TResult {
  const {
    type,
    data: inputData,
    actor: rootActor,
    requestId,
    analyticsMetadata,
    origin,
    source: inputSource,
    subjects: inputSubjects,
    organizationId,
    organizationSlug,
    projectId,
    projectSlug,
    category = 'product',
    // Since we don't have a signal type in the event payload, we default to log.
    signal = 'log',
    osPlatform,
    userAgent,
  } = options;

  const hasDirectArray = !!(inputData && Array.isArray(inputData));

  const actor: CloudEventActor | null = rootActor
    ? {
        id: rootActor.id ?? `ann_${ulid()}`,
        object: rootActor.object ?? 'user',
        uri: (rootActor.uri ?? '') as string,
      }
    : null;
  const id = `evt_${ulid()}`.toLowerCase();
  const time = new Date();

  const source = inputSource ?? actor?.uri ?? null;

  const contextFields: Partial<CloudEventMapperResult> = {
    ...(organizationId !== undefined && { organizationId }),
    ...(organizationSlug !== undefined && { organizationSlug }),
    ...(projectId !== undefined && { projectId }),
    ...(projectSlug !== undefined && { projectSlug }),
  };

  const result: Partial<CloudEventMapperResult> & Record<string, unknown> = {
    specversion: '1.0',
    object: 'event',
    // Ref: https://github.com/cloudevents/spec/blob/v1.0.2/cloudevents/spec.md#datacontenttype
    datacontenttype: 'application/json; charset=utf-8',
    origin,
    category,
    signal,
    osPlatform,
    userAgent,
  };

  if (hasDirectArray) {
    const dataArray = inputData as CloudEventMapperDataItem[];

    const subjects =
      inputSubjects ||
      dataArray.map((item: CloudEventMapperDataItem) => ({
        id: item.id ?? '',
        object: item.object ?? 'unknown',
        uri: item.uri ?? '',
      }));

    // Subject is the primary resource identifier from data[0]
    const subject = (dataArray[0] as CloudEventMapperDataItem)?.id ?? null;

    Object.assign(result, {
      ...contextFields,
      id,
      type,
      time,
      source,
      actor,
      subject,
      subjects,
      context: { ip: analyticsMetadata?.userIpAddress },
      data: dataArray,
      requestId: requestId ?? '',
      analyticsMetadata,
    });
  } else {
    // UI/Client-specific mapping (for telemetry client)
    // Subject for UI-side: extract from data if array, or use data.id if object
    const subject = (Array.isArray(inputData) ? inputData[0] : inputData)?.id ?? null;

    Object.assign(result, {
      ...contextFields,
      id,
      type,
      time,
      source,
      actor,
      subject,
      requestId: requestId ?? '',
      data: inputData,
      // Preserve request for OTEL attributes (cloudevents.request.source)
      ...(inputSource != null && { request: { source: inputSource } }),
    });
  }

  return result as TResult;
}
