// Standalone attribute types (no @opentelemetry/api dependency)
type AttributeValue = string | number | boolean | undefined;
type Attributes = Record<string, AttributeValue>;

type OtelClientConfig = {
  version?: string;
  serviceName?: string;
};

import type {
  CloudEventMapperResult,
  CloudEventMapperDataItem,
  CloudEventMapperSubjectsArray,
} from '../cloudEvents';
import { CLOUD_EVENT_STANDARD_KEYS } from '../cloudEvents';

type ItemWithObject = { object: string; [key: string]: unknown };

export type GroupedItems = {
  updated: ItemWithObject[];
  notUpdated: ItemWithObject[];
};

// --- String utilities ---

export function toSnakeCase(str: string): string {
  return str.replace(/([A-Z])/g, '_$1').toLowerCase();
}

type GroupableItem = CloudEventMapperDataItem | CloudEventMapperSubjectsArray[number];

/**
 * Groups items by their `object` property, detecting before/after pairs.
 * Used for event data (CloudEventMapperDataItem[]) and subjects (CloudEventMapperSubjectsArray).
 */
export function groupByObjectProperty(items: Array<GroupableItem | unknown>): GroupedItems {
  const result: GroupedItems = { updated: [], notUpdated: [] };

  for (const item of items) {
    if (!item || typeof item !== 'object') {
      continue;
    }

    const objectType = (item as { object?: unknown }).object;
    if (!objectType || typeof objectType !== 'string') {
      continue;
    }

    const itemTyped = item as ItemWithObject;
    const existingInNotUpdated = result.notUpdated.find((entry) => entry.object === objectType);

    if (existingInNotUpdated) {
      result.updated = [existingInNotUpdated, itemTyped];
      result.notUpdated = result.notUpdated.filter((entry) => entry.object !== objectType);
    } else if (!result.updated.some((entry) => entry.object === objectType)) {
      result.notUpdated.push(itemTyped);
    }
  }

  return result;
}

/**
 * Flattens an object's properties into OTEL attributes with a given prefix.
 */
export function flattenToAttributes(
  data: Record<string, unknown>,
  prefix: string,
  attributes: Attributes,
  useSnakeCase = true,
): void {
  for (const [key, value] of Object.entries(data)) {
    if (value !== undefined) {
      const formattedKey = useSnakeCase ? toSnakeCase(key) : key;
      attributes[`${prefix}${formattedKey}`] = value as string;
    }
  }
}

/**
 * Flattens nested object properties (one level deep) into OTEL attributes.
 * Processes string, number, and boolean primitives. Skips null, undefined, and nested objects.
 */
export function flattenNestedObject(
  obj: Record<string, unknown>,
  prefix: string,
  attributes: Attributes,
): void {
  for (const [key, value] of Object.entries(obj)) {
    if (value === undefined || value === null || typeof value === 'object') {
      continue;
    }
    attributes[`${prefix}.${toSnakeCase(key)}`] = value as string | number | boolean;
  }
}

// --- CloudEvent → OTEL Attributes (CloudEvent is source of truth) ---

export type CloudEventBaseAttributes = Record<string, string | number | undefined>;

function buildBaseAttributes(
  cloudEvent: CloudEventMapperResult,
  time: Date,
  config?: OtelClientConfig | null,
): CloudEventBaseAttributes {
  const timeStr = time instanceof Date ? time.toISOString() : new Date(time).toISOString();
  const base: CloudEventBaseAttributes = {
    'cloudevents.event_id': cloudEvent.id,
    'cloudevents.event_type': cloudEvent.type,
    'cloudevents.event_source': cloudEvent.source ?? undefined,
    'cloudevents.event_spec_version': cloudEvent.specversion,
    'cloudevents.event_data_content_type':
      cloudEvent.datacontenttype ?? 'application/json; charset=utf-8',
    'cloudevents.event_time': timeStr,
    'cloudevents.event_subject': cloudEvent.subject ?? '',
    'cloudevents.page.uri': typeof location !== 'undefined' ? location.href : undefined,
    'cloudevents.event_version': config?.version,
    'cloudevents.event_origin': cloudEvent.origin ?? config?.serviceName,
    'cloudevents.event_source_details.id': cloudEvent.actor?.id ?? 'anonymous',
    'cloudevents.event_source_details.object': cloudEvent.actor?.object ?? 'anonymous',
    'cloudevents.event_source_details.uri': cloudEvent.actor?.uri ?? undefined,
    'cloudevents.metadata.user_id': cloudEvent.analyticsMetadata?.userId,
    'cloudevents.metadata.user_ip_address': cloudEvent.analyticsMetadata?.userIpAddress,
    // Match main branch naming (was processExtensionAttributes output)
    'cloudevents.event_object': cloudEvent.object || 'event',
    // @deprecated key `cloudevents.object`
    'cloudevents.object': cloudEvent.object || 'event',
    'cloudevents.event_category': cloudEvent.category,
    'cloudevents.event_signal': cloudEvent.signal,
    'cloudevents.origin': cloudEvent.origin,
    'cloudevents.event_actor.id': cloudEvent.actor?.id ?? undefined,
    'cloudevents.event_actor.object': cloudEvent.actor?.object ?? undefined,
    'cloudevents.event_actor.uri': cloudEvent.actor?.uri ?? undefined,
    'cloudevents.event_organization_id': cloudEvent.organizationId,
    'cloudevents.event_organization_slug': cloudEvent.organizationSlug,
    'cloudevents.event_project_id': cloudEvent.projectId,
    'cloudevents.event_project_slug': cloudEvent.projectSlug,
    'cloudevents.event_request_id': cloudEvent.requestId,
    // @deprecated keys
    'cloudevents.requestId': cloudEvent.requestId,
    'cloudevents.organizationId': cloudEvent.organizationId,
    'cloudevents.organizationSlug': cloudEvent.organizationSlug,
    'cloudevents.projectId': cloudEvent.projectId,
    'cloudevents.projectSlug': cloudEvent.projectSlug,
    'cloudevents.event_os_platform': cloudEvent.osPlatform,
    'cloudevents.event_user_agent': cloudEvent.userAgent,
  };

  return base;
}

/**
 * Processes a CloudEvent into OpenTelemetry span attributes.
 * CloudEventMapperResult is the single source of truth (from cloudEvents/mapper).
 */
export function processCloudEventAttributes(
  cloudEvent: CloudEventMapperResult,
  time: Date,
  config?: OtelClientConfig | null,
): Attributes {
  const eventData = cloudEvent.data;

  const attributes: Attributes = {
    ...buildBaseAttributes(cloudEvent, time, config),
    ...extractFieldAttributes('project', cloudEvent),
    ...extractFieldAttributes('organization', cloudEvent),
  };

  processEventData(eventData, attributes);
  processSubjects(cloudEvent, attributes);
  processExtensionAttributes(cloudEvent, attributes);

  return attributes;
}

function processEventData(eventData: unknown, attributes: Attributes): void {
  if (!eventData || typeof eventData !== 'object') {
    return;
  }

  if (Array.isArray(eventData)) {
    processArrayData(eventData, attributes);
  } else {
    processObjectData(eventData as Record<string, unknown>, attributes);
  }
}

function processArrayData(eventData: unknown[], attributes: Attributes): void {
  const hasObjectProperty = eventData.some(
    (item: any) => item && typeof item === 'object' && typeof item.object === 'string',
  );

  if (hasObjectProperty) {
    processEventBusStyleData(eventData, attributes);
  } else {
    processSimpleArrayData(eventData, attributes);
  }
}

function processEventBusStyleData(eventData: unknown[], attributes: Attributes): void {
  const grouped = groupByObjectProperty(eventData);

  grouped.updated.forEach((data: any, index: number) => {
    const prefix = `cloudevents.event_data.${index === 0 ? 'after.' : 'before.'}${data.object}.`;
    flattenToAttributes(data, prefix, attributes);
  });

  grouped.notUpdated.forEach((data: any) => {
    const prefix = `cloudevents.event_data.${data.object}.`;
    flattenToAttributes(data, prefix, attributes);
  });
}

function processSimpleArrayData(eventData: unknown[], attributes: Attributes): void {
  for (const item of eventData) {
    if (!item || typeof item !== 'object') {
      continue;
    }

    for (const [key, value] of Object.entries(item as Record<string, unknown>)) {
      if (value === undefined) {
        continue;
      }

      const keySnakeCase = toSnakeCase(key);

      if (value !== null && typeof value === 'object' && !Array.isArray(value)) {
        flattenNestedObject(
          value as Record<string, unknown>,
          `cloudevents.event_data.${keySnakeCase}`,
          attributes,
        );
      } else {
        attributes[`cloudevents.event_data.${keySnakeCase}`] = value as string | number;
      }
    }
  }
}

/**
 * Processes event data object into CloudEvents event_data attributes.
 * Exported for use by ReporterTelemetryClient.
 */
export function processObjectData(
  eventData: Record<string, unknown>,
  attributes: Attributes,
): void {
  for (const [key, value] of Object.entries(eventData)) {
    if (value === undefined || value === null) {
      continue;
    }

    const keySnakeCase = toSnakeCase(key);

    if (typeof value === 'object' && !Array.isArray(value)) {
      for (const [nestedKey, nestedValue] of Object.entries(value)) {
        if (nestedValue !== undefined && nestedValue !== null) {
          // Note: nested keys are NOT converted to snake_case (preserving original key names)
          if (
            typeof nestedValue === 'string' ||
            typeof nestedValue === 'number' ||
            typeof nestedValue === 'boolean'
          ) {
            attributes[`cloudevents.event_data.${keySnakeCase}.${nestedKey}`] = nestedValue;
          }
        }
      }
    } else if (
      typeof value === 'string' ||
      typeof value === 'number' ||
      typeof value === 'boolean'
    ) {
      attributes[`cloudevents.event_data.${keySnakeCase}`] = value;
    }
  }
}

function processSubjects(event: CloudEventMapperResult, attributes: Attributes): void {
  if (!event.subjects || !Array.isArray(event.subjects)) {
    return;
  }

  const grouped = groupByObjectProperty(event.subjects);

  grouped.updated.forEach((subject: any, index: number) => {
    const prefix = `cloudevents.subjects.${index === 0 ? 'after.' : 'before.'}${subject.object}.`;
    flattenToAttributes(subject, prefix, attributes, false);
  });

  grouped.notUpdated.forEach((subject: any) => {
    const prefix = `cloudevents.subjects.${subject.object}.`;
    flattenToAttributes(subject, prefix, attributes, false);
  });
}

function processExtensionAttributes(
  cloudEvent: CloudEventMapperResult,
  attributes: Attributes,
): void {
  for (const [key, value] of Object.entries(cloudEvent)) {
    if (CLOUD_EVENT_STANDARD_KEYS.includes(key) || value === undefined) {
      continue;
    }

    if (value instanceof Object) {
      for (const [nestedKey, nestedValue] of Object.entries(value)) {
        if (nestedValue !== undefined) {
          attributes[`cloudevents.${key}.${nestedKey}`] = nestedValue as string;
        }
      }
    } else {
      attributes[`cloudevents.${key}`] = value as string;
    }
  }
}

function extractFieldAttributes(
  fieldName: 'project' | 'organization',
  cloudEvent: CloudEventMapperResult,
): Record<string, string | number> {
  const fieldIdKey = `${fieldName}Id` as keyof CloudEventMapperResult;
  const fieldSlugKey = `${fieldName}Slug` as keyof CloudEventMapperResult;

  const fieldId = cloudEvent[fieldIdKey];
  const fieldSlug = cloudEvent[fieldSlugKey];
  if (fieldId !== undefined && fieldSlug !== undefined) {
    return {
      [`cloudevents.${fieldName}.id`]: fieldId as string,
      [`cloudevents.${fieldName}.slug`]: fieldSlug as string,
    };
  }

  // Store data in a variable with proper type to avoid TypeScript narrowing issues
  // event.data can be an array (API messages) or an object (UI messages)
  const eventData = cloudEvent.data;
  if (Array.isArray(eventData) && eventData.length) {
    const resource = eventData.find(
      (resource: CloudEventMapperDataItem) => resource?.object === fieldName,
    ) as (CloudEventMapperDataItem & { id: string; slug: string }) | undefined;
    return resource
      ? {
          [`cloudevents.${fieldName}.id`]: resource.id,
          [`cloudevents.${fieldName}.slug`]: resource.slug,
        }
      : {};
  }
  return {};
}

/** @deprecated Use OtelClientConfig */
export type ProcessCloudEventAttributesConfig = OtelClientConfig;

/**
 * Processes CloudEvent attributes for OpenTelemetry spans.
 * CloudEvent<T> extends CloudEventMapperResult, so typed events are accepted.
 */
export function processAttributes(
  cloudEvent: CloudEventMapperResult,
  time: Date,
  config?: OtelClientConfig | null,
): Attributes {
  return processCloudEventAttributes(cloudEvent, time, config);
}
